INSERT INTO "public"."cesafi_timeline" ("id", "created_at", "updated_at", "year", "title", "description", "category", "is_highlight", "image_url") VALUES ('4', '2025-09-26 12:58:10.090385+00', '2025-09-26 12:58:10.090385+00', '2001', 'CESAFI was born', 'In 2001, Felix "Boy" Tiukinhoy Jr. founded the Cebu Schools Athletic Foundation, Inc. (CESAFI).', 'founding', 'true', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1758891443/timeline/events/CESAFI-OFFICIAL-LOGO-2022-COLORED-01-1758891439943.png'), ('5', '2025-09-26 13:10:18.210969+00', '2025-09-26 13:10:18.210969+00', '2022', 'CESAFI Esports League (CEL) was added ', 'The CEL launched its inaugural regular season in December 2022, and the organization grew as the number of dedicated student volunteers and competitive student-athletes increased.', 'expansion', 'true', 'https://res.cloudinary.com/dbm5rzesq/image/upload/v1758892209/timeline/events/download-1758892206980.jpg');